76	func BuildGraphWithConfig(workingDir string) (*Graph, error) {
77		configs, err := LoadGraphConfigs(workingDir)
78		if err != nil {
79			return nil, err
80		}
81		if len(configs) == 0 {
82			return BuildGraph(workingDir)
83		}
84	
85		roots := make([]string, 0, len(configs))
86		for _, cfg := range configs {
87			for _, root := range cfg.Roots {
88				if root == "" {
89					continue
90				}
91				roots = append(roots, filepath.Join(workingDir, root))
92			}
93		}
94		if len(roots) == 0 {
95			return BuildGraph(workingDir)
96		}
97	
98		graph, err := buildGraph(workingDir, roots)
99		if err != nil {
100			return nil, err
101		}
102		graph.applyConfig(configs)
103		return graph, nil
104	}
