106	func buildGraph(workingDir string, roots []string) (*Graph, error) {
107		files, err := findMarkdownFiles(workingDir, roots)
108		if err != nil {
109			return nil, err
110		}
111	
112		documents := make(map[string]*Document)
113		pathToID := make(map[string]string)
114		warnings := []string{}
115		for _, filePath := range files {
116			doc, err := ParseDocument(filePath)
117			if err != nil {
118				if errors.Is(err, ErrNotDocGraphDocument) {
119					continue
120				}
121				warnings = append(warnings, fmt.Sprintf("%s: %v", filePath, err))
122				continue
123			}
124			if _, exists := documents[doc.ID]; exists {
125				warnings = append(warnings, fmt.Sprintf("duplicate document id %q in %q", doc.ID, filePath))
126				continue
127			}
128			doc.Path = filepath.Clean(filePath)
129			documents[doc.ID] = doc
130			pathToID[doc.Path] = doc.ID
131		}
132	
133		g := &Graph{
134			RootDir:   filepath.Clean(workingDir),
135			Documents: documents,
136			PathToID:  pathToID,
137			Warnings:  warnings,
138		}
139		g.resolveBodyLinks()
140		g.buildDependents()
141		g.detectCycles()
142		g.applyConfigDefaults()
143		return g, nil
144	}
