146	func (g *Graph) applyConfigDefaults() {
147		for _, doc := range g.Documents {
148			doc.DependsOn = dedupeSortedStrings(doc.DependsOn)
149			doc.Inputs = dedupeSortedStrings(doc.Inputs)
150		}
151	}
