153	func (g *Graph) applyConfig(configs []GraphConfig) {
154		if len(configs) == 0 {
155			return
156		}
157	
158		idToPath := make(map[string]string)
159		cascade := make(map[string][]string)
160		for _, cfg := range configs {
161			for id, rawPath := range cfg.IDToPath {
162				if id == "" || rawPath == "" {
163					continue
164				}
165				idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
166			}
167			for from, tos := range cfg.Cascade {
168				for _, to := range tos {
169					if from == "" || to == "" {
170						continue
171					}
172					cascade[from] = append(cascade[from], to)
173				}
174			}
175			if len(cfg.IDMap) > 0 {
176				for id, rawPath := range cfg.IDMap {
177					if id == "" || rawPath == "" {
178						continue
179					}
180					idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
181				}
182			}
183			if len(cfg.Required) > 0 {
184				for _, id := range cfg.Required {
185					if _, ok := g.Documents[id]; !ok {
186						g.Warnings = append(g.Warnings, fmt.Sprintf("required root document %q not found", id))
187					}
188				}
189			}
190		}
191	
192		if len(idToPath) > 0 {
193			for id, path := range idToPath {
194				if _, ok := g.Documents[id]; ok {
195					continue
196				}
197				if _, err := os.Stat(path); err != nil {
198					g.Warnings = append(g.Warnings, fmt.Sprintf("id_to_path entry %q -> %q does not exist", id, path))
199					continue
200				}
201				doc, err := ParseDocument(path)
202				if err != nil {
203					if errors.Is(err, ErrNotDocGraphDocument) {
204						g.Warnings = append(g.Warnings, fmt.Sprintf("id_to_path entry %q -> %q is not a doc graph document", id, path))
205						continue
206					}
207					g.Warnings = append(g.Warnings, fmt.Sprintf("id_to_path entry %q -> %q could not be loaded: %v", id, path, err))
208					continue
209				}
210				if doc.ID != id {
211					g.Warnings = append(g.Warnings, fmt.Sprintf("id_to_path mismatch for %q: %q declares %q", id, path, doc.ID))
212					continue
213				}
214				g.Documents[id] = doc
215				doc.Path = filepath.Clean(path)
216				g.PathToID[doc.Path] = id
217			}
218		}
219	
220		for from, toIDs := range cascade {
221			if _, ok := g.Documents[from]; !ok {
222				g.Warnings = append(g.Warnings, fmt.Sprintf("cascade rule refers to unknown dependency root %q", from))
223				continue
224			}
225			for _, to := range dedupeSortedStrings(toIDs) {
226				if to == "" {
227					continue
228				}
229				child, ok := g.Documents[to]
230				if !ok {
231					g.Warnings = append(g.Warnings, fmt.Sprintf("cascade rule refers to unknown target doc %q", to))
232					continue
233				}
234				if !containsString(child.DependsOn, from) {
235					child.DependsOn = append(child.DependsOn, from)
236				}
237			}
238		}
239	
240		for id := range g.Documents {
241			g.Documents[id].DependsOn = dedupeSortedStrings(g.Documents[id].DependsOn)
242		}
243		g.buildDependents()
244		g.detectCycles()
245	}
