247	func findMarkdownFiles(root string, roots []string) ([]string, error) {
248		targetDirs := []string{root}
249		if len(roots) > 0 {
250			targetDirs = roots
251		}
252	
253		files := []string{}
254		for _, base := range targetDirs {
255			cleanRoot := filepath.Clean(base)
256			err := filepath.Walk(cleanRoot, func(path string, info os.FileInfo, err error) error {
257				if err != nil {
258					return nil
259				}
260				if info == nil {
261					return nil
262				}
263				if info.IsDir() {
264					name := filepath.Base(path)
265					switch name {
266					case ".git", ".ddx":
267						return filepath.SkipDir
268					}
269					return nil
270				}
271				if strings.HasPrefix(filepath.Base(path), ".") {
272					return nil
273				}
274				ext := strings.ToLower(filepath.Ext(path))
275				if ext != ".md" {
276					return nil
277				}
278				files = append(files, path)
279				return nil
280			})
281			if err != nil {
282				return nil, err
283			}
284		}
285		sort.Strings(files)
286		return files, nil
287	}
