289	func ParseDocument(path string) (*Document, error) {
290		content, err := os.ReadFile(path)
291		if err != nil {
292			return nil, err
293		}
294	
295		frontmatter, body, err := ParseFrontmatter(content)
296		if err != nil {
297			return nil, err
298		}
299		if !frontmatter.HasFrontmatter || frontmatter.Doc.ID == "" {
300			return nil, fmt.Errorf("%w in %s", ErrNotDocGraphDocument, path)
301		}
302	
303		review := ReviewMetadata{
304			SelfHash:   frontmatter.Doc.Review.SelfHash,
305			ReviewedAt: frontmatter.Doc.Review.ReviewedAt,
306			Deps:       frontmatter.Doc.Review.Deps,
307		}
308		if review.Deps == nil {
309			review.Deps = map[string]string{}
310		}
311	
312		doc := &Document{
313			ID:            frontmatter.Doc.ID,
314			Title:         extractTitle([]byte(body)),
315			DependsOn:     dedupeSortedStrings(frontmatter.Doc.DependsOn),
316			Inputs:        dedupeSortedStrings(frontmatter.Doc.Inputs),
317			Review:        review,
318			ParkingLot:    frontmatter.Doc.ParkingLot,
319			Prompt:        frontmatter.Doc.Prompt,
320			ExecDef:       frontmatter.Doc.Exec,
321			body:          body,
322			bodyLinkTexts: extractBodyLinks(body),
323		}
324		if frontmatter.Raw != nil {
325			doc.frontmatter = frontmatter.Raw
326		}
327	
328		contentHash, err := HashDocument(frontmatter.Raw, body)
329		if err != nil {
330			return nil, err
331		}
332		doc.contentHash = contentHash
333		return doc, nil
334	}
