336	func (g *Graph) buildDependents() {
337		g.Dependents = make(map[string][]string)
338		for id := range g.Documents {
339			g.Dependents[id] = g.Dependents[id][:0]
340		}
341		for id, doc := range g.Documents {
342			for _, dep := range doc.DependsOn {
343				if _, ok := g.Documents[dep]; !ok {
344					continue
345				}
346				if containsString(g.Dependents[dep], id) {
347					continue
348				}
349				g.Dependents[dep] = append(g.Dependents[dep], id)
350			}
351		}
352		for id := range g.Dependents {
353			g.Dependents[id] = dedupeSortedStrings(g.Dependents[id])
354		}
355		for id, doc := range g.Documents {
356			doc.Dependents = append([]string{}, g.Dependents[id]...)
357		}
358	}
