360	func (g *Graph) detectCycles() {
361		index := 0
362		indexes := map[string]int{}
363		lowlinks := map[string]int{}
364		onStack := map[string]bool{}
365		stack := []string{}
366		warned := map[string]struct{}{}
367		var visit func(string)
368	
369		visit = func(id string) {
370			indexes[id] = index
371			lowlinks[id] = index
372			index++
373			stack = append(stack, id)
374			onStack[id] = true
375	
376			node := g.Documents[id]
377			for _, dep := range node.DependsOn {
378				if _, ok := g.Documents[dep]; !ok {
379					continue
380				}
381				if _, ok := indexes[dep]; !ok {
382					visit(dep)
383					if lowlinks[dep] < lowlinks[id] {
384						lowlinks[id] = lowlinks[dep]
385					}
386				} else if onStack[dep] {
387					if indexes[dep] < lowlinks[id] {
388						lowlinks[id] = indexes[dep]
389					}
390				}
391			}
392	
393			if lowlinks[id] == indexes[id] {
394				cycle := []string{}
395				for {
396					last := stack[len(stack)-1]
397					stack = stack[:len(stack)-1]
398					onStack[last] = false
399					cycle = append(cycle, last)
400					if last == id {
401						break
402					}
403				}
404				if len(cycle) > 1 {
405					warnKey := cycleKey(cycle)
406					if _, done := warned[warnKey]; done {
407						return
408					}
409					warned[warnKey] = struct{}{}
410					label := renderCycle(cycle)
411					g.Warnings = append(g.Warnings, fmt.Sprintf("cycle detected: %s", label))
412				} else {
413					parent := g.Documents[id]
414					selfDepends := containsString(parent.DependsOn, id)
415					if selfDepends {
416						label := fmt.Sprintf("%s -> %s", id, id)
417						g.Warnings = append(g.Warnings, fmt.Sprintf("cycle detected: %s", label))
418					}
419				}
420			}
421		}
422	
423		for id := range g.Documents {
424			if _, ok := indexes[id]; !ok {
425				visit(id)
426			}
427		}
428	
429		sort.Strings(g.Warnings)
430	}
