432	func cycleKey(ids []string) string {
433		if len(ids) == 0 {
434			return ""
435		}
436		copyIDs := append([]string(nil), ids...)
437		sort.Strings(copyIDs)
438		return strings.Join(copyIDs, "::")
439	}
