441	func renderCycle(ids []string) string {
442		if len(ids) == 0 {
443			return ""
444		}
445		copyIDs := append([]string(nil), ids...)
446		sort.Strings(copyIDs)
447		start := copyIDs[0]
448		return start + " -> " + strings.Join(copyIDs[1:], " -> ") + " -> " + start
449	}
