451	func (g *Graph) StaleDocs() []StaleReason {
452		if len(g.Documents) == 0 {
453			return nil
454		}
455	
456		direct := map[string][]string{}
457		for id := range g.Documents {
458			doc, ok := g.Documents[id]
459			if !ok || doc.ParkingLot {
460				continue
461			}
462			reasons := staleReasonsForDocument(g, doc)
463			if len(reasons) > 0 {
464				direct[id] = reasons
465			}
466		}
467	
468		final := map[string][]string{}
469		queue := []string{}
470		for id, reasons := range direct {
471			final[id] = append([]string(nil), reasons...)
472			queue = append(queue, id)
473		}
474	
475		seen := map[string]struct{}{}
476		for _, id := range queue {
477			seen[id] = struct{}{}
478		}
479		for i := 0; i < len(queue); i++ {
480			u := queue[i]
481			for _, dep := range g.Dependents[u] {
482				child, ok := g.Documents[dep]
483				if !ok || child.ParkingLot {
484					continue
485				}
486				if _, done := seen[dep]; done {
487					continue
488				}
489				seen[dep] = struct{}{}
490				final[dep] = []string{"upstream stale dependency"}
491				queue = append(queue, dep)
492			}
493		}
494	
495		ids := make([]string, 0, len(final))
496		for id := range final {
497			ids = append(ids, id)
498		}
499		sort.Strings(ids)
500		result := make([]StaleReason, 0, len(ids))
501		for _, id := range ids {
502			doc := g.Documents[id]
503			reason := StaleReason{ID: id, Path: doc.Path, Reasons: final[id]}
504			sort.Strings(reason.Reasons)
505			result = append(result, reason)
506		}
507		return result
508	}
