510	func staleReasonsForDocument(g *Graph, doc *Document) []string {
511		reasons := []string{}
512		for _, depID := range doc.DependsOn {
513			depDoc, ok := g.Documents[depID]
514			if !ok {
515				reasons = append(reasons, fmt.Sprintf("missing dependency: %s", depID))
516				continue
517			}
518			expected := doc.Review.Deps[depID]
519			if expected == "" {
520				reasons = append(reasons, fmt.Sprintf("missing review hash for dependency: %s", depID))
521				continue
522			}
523			if expected != depDoc.contentHash {
524				reasons = append(reasons, fmt.Sprintf("dependency changed: %s", depID))
525			}
526		}
527		return dedupeSortedStrings(reasons)
528	}
