530	func (g *Graph) StaleReasonForID(id string) (StaleReason, bool) {
531		stale := g.StaleDocs()
532		for _, entry := range stale {
533			if entry.ID == id {
534				return entry, true
535			}
536		}
537		doc, ok := g.Documents[id]
538		if !ok {
539			return StaleReason{}, false
540		}
541		return StaleReason{ID: id, Path: doc.Path, Reasons: nil}, true
542	}
