564	func (g *Graph) ResolvePathsToIDs(targets []string) ([]string, error) {
565		ids := make([]string, 0, len(targets))
566		seen := map[string]struct{}{}
567		for _, target := range targets {
568			if target == "" {
569				continue
570			}
571			if id, ok := g.Documents[target]; ok {
572				if _, done := seen[id.ID]; !done {
573					seen[id.ID] = struct{}{}
574					ids = append(ids, id.ID)
575				}
576				continue
577			}
578			resolved := target
579			if !filepath.IsAbs(resolved) {
580				resolved = filepath.Join(g.RootDir, resolved)
581			}
582			resolved = filepath.Clean(resolved)
583			if id, ok := g.PathToID[resolved]; ok {
584				if _, done := seen[id]; !done {
585					seen[id] = struct{}{}
586					ids = append(ids, id)
587				}
588				continue
589			}
590			if info, err := os.Stat(resolved); err == nil && info.IsDir() {
591				err := filepath.Walk(resolved, func(path string, info os.FileInfo, err error) error {
592					if err != nil {
593						return nil
594					}
595					if info.IsDir() {
596						if info.Name() == ".git" || info.Name() == ".ddx" {
597							return filepath.SkipDir
598						}
599						return nil
600					}
601					if strings.EqualFold(filepath.Ext(path), ".md") {
602						cleanPath := filepath.Clean(path)
603						if id, ok := g.PathToID[cleanPath]; ok {
604							if _, done := seen[id]; !done {
605								seen[id] = struct{}{}
606								ids = append(ids, id)
607							}
608						}
609					}
610					return nil
611				})
612				if err != nil {
613					return nil, err
614				}
615				continue
616			}
617			return nil, fmt.Errorf("cannot resolve target %q", target)
618		}
619		if len(ids) == 0 {
620			return nil, fmt.Errorf("no matching targets")
621		}
622		return dedupeSortedStrings(ids), nil
623	}
