625	func (g *Graph) Stamp(targets []string, now time.Time) ([]string, []string, error) {
626		docIDs, err := g.ResolvePathsToIDs(targets)
627		if err != nil {
628			return nil, nil, err
629		}
630	
631		stamped := make([]string, 0, len(docIDs))
632		warnings := []string{}
633		for _, id := range docIDs {
634			doc, ok := g.Documents[id]
635			if !ok {
636				warnings = append(warnings, fmt.Sprintf("document %q not found", id))
637				continue
638			}
639			if doc.frontmatter == nil {
640				warnings = append(warnings, fmt.Sprintf("document %q missing frontmatter", id))
641				continue
642			}
643			review := ReviewMetadata{
644				SelfHash:   doc.contentHash,
645				ReviewedAt: now.UTC().Format(time.RFC3339),
646				Deps:       map[string]string{},
647			}
648			for _, depID := range doc.DependsOn {
649				if dep, ok := g.Documents[depID]; ok {
650					review.Deps[depID] = dep.contentHash
651				}
652			}
653			if review.Deps == nil {
654				review.Deps = map[string]string{}
655			}
656			reviewForWrite := DocReview(review)
657			err := SetReview(doc.frontmatter, reviewForWrite)
658			if err != nil {
659				return stamped, warnings, err
660			}
661			frontmatterText, err := EncodeFrontmatter(doc.frontmatter)
662			if err != nil {
663				return stamped, warnings, err
664			}
665			updated := frontmatterSeparator + "\n" + frontmatterText + "\n" + frontmatterSeparator + "\n" + doc.body
666			if err := os.WriteFile(doc.Path, []byte(updated), 0644); err != nil {
667				return stamped, warnings, err
668			}
669			if doc.Review.ReviewedAt == "" || doc.Review.SelfHash != review.SelfHash {
670				doc.Review = review
671			}
672			stamped = append(stamped, id)
673		}
674		sort.Strings(stamped)
675		return stamped, warnings, nil
676	}
