708	func extractTitle(body []byte) string {
709		for _, line := range strings.Split(normalizeNewlines(string(body)), "\n") {
710			trimmed := strings.TrimSpace(line)
711			if strings.HasPrefix(trimmed, "# ") {
712				return strings.TrimSpace(strings.TrimPrefix(trimmed, "# "))
713			}
714		}
715		return ""
716	}
717	
718	func dedupeSortedStrings(values []string) []string {
719		seen := map[string]struct{}{}
720		out := make([]string, 0, len(values))
721		for _, value := range values {
722			v := strings.TrimSpace(value)
723			if v == "" {
724				continue
725			}
726			if _, ok := seen[v]; ok {
727				continue
728			}
729			seen[v] = struct{}{}
730			out = append(out, v)
731		}
732		sort.Strings(out)
733		return out
734	}
735	
736	func containsString(values []string, target string) bool {
737		for _, value := range values {
738			if value == target {
739				return true
740			}
741		}
742		return false
743	}
744	
745	var bodyLinkPattern = regexp.MustCompile(`\[\[([^\[\]]+)\]\]`)
746	
747	// extractBodyLinks returns the raw text inside every [[...]] span in body.
748	// Nested or malformed brackets are skipped.
749	func extractBodyLinks(body string) []string {
750		matches := bodyLinkPattern.FindAllStringSubmatch(body, -1)
751		if len(matches) == 0 {
752			return nil
753		}
754		out := make([]string, 0, len(matches))
755		for _, m := range matches {
756			text := strings.TrimSpace(m[1])
757			if text != "" {
758				out = append(out, text)
759			}
760		}
761		return out
762	}
763	
764	// slugifyID converts a wikilink label into a lowercase-hyphen slug suitable
765	// for ID matching. Dots are preserved (dotted IDs). Spaces and underscores
766	// become hyphens. Other non-alphanumeric characters are dropped.
767	func slugifyID(text string) string {
768		var b strings.Builder
769		prevHyphen := false
770		for _, r := range strings.ToLower(text) {
771			switch {
772			case unicode.IsLetter(r) || unicode.IsDigit(r) || r == '.':
773				b.WriteRune(r)
774				prevHyphen = false
775			case r == '-' || r == '_' || unicode.IsSpace(r):
776				if !prevHyphen && b.Len() > 0 {
777					b.WriteByte('-')
778					prevHyphen = true
779				}
780			}
781		}
782		result := b.String()
783		return strings.TrimRight(result, "-")
784	}
785	
786	// resolveBodyLinks merges body [[ID]] references into each document's DependsOn.
787	func (g *Graph) resolveBodyLinks() {
788		for _, doc := range g.Documents {
789			if len(doc.bodyLinkTexts) == 0 {
790				continue
791			}
792			for _, text := range doc.bodyLinkTexts {
793				resolved := resolveBodyLinkText(text, g.Documents)
794				if resolved == "" || resolved == doc.ID {
795					continue
796				}
797				if !containsString(doc.DependsOn, resolved) {
798					doc.DependsOn = append(doc.DependsOn, resolved)
799				}
800			}
801			doc.DependsOn = dedupeSortedStrings(doc.DependsOn)
802		}
803	}
804	
805	// resolveBodyLinkText tries to resolve a raw wikilink text to a document ID.
806	// Resolution order: exact match, then slug match.
807	func resolveBodyLinkText(text string, docs map[string]*Document) string {
808		if _, ok := docs[text]; ok {
809			return text
810		}
811		slug := slugifyID(text)
812		if slug != text {
813			if _, ok := docs[slug]; ok {
814				return slug
815			}
816		}
817		return ""
818	}
