820	func LoadGraphConfigs(workingDir string) ([]GraphConfig, error) {
821		cfgDir := filepath.Join(workingDir, ".ddx", "graphs")
822		entries, err := os.ReadDir(cfgDir)
823		if err != nil {
824			if os.IsNotExist(err) {
825				return nil, nil
826			}
827			return nil, err
828		}
829	
830		configs := []GraphConfig{}
831		for _, entry := range entries {
832			if entry.IsDir() {
833				continue
834			}
835			ext := strings.ToLower(filepath.Ext(entry.Name()))
836			if ext != ".yml" && ext != ".yaml" {
837				continue
838			}
839			cfgPath := filepath.Join(cfgDir, entry.Name())
840			raw, err := os.ReadFile(cfgPath)
841			if err != nil {
842				return nil, fmt.Errorf("read graph config %q: %w", cfgPath, err)
843			}
844			var cfg GraphConfig
845			if err := yaml.Unmarshal(raw, &cfg); err != nil {
846				return nil, fmt.Errorf("parse graph config %q: %w", cfgPath, err)
847			}
848			configs = append(configs, cfg)
849		}
850		sort.Slice(configs, func(i, j int) bool {
851			return len(configs[i].Roots) > len(configs[j].Roots)
852		})
853		return configs, nil
854	}
