16	// DocumentByPath is the resolver for the documentByPath field.
17	// It reads the document at the given library-relative path and returns its
18	// metadata (from the docgraph) plus the raw file content.
19	func (r *queryResolver) DocumentByPath(ctx context.Context, path string) (*Document, error) {
20		if path == "" {
21			return nil, fmt.Errorf("path is required")
22		}
23	
24		cleaned := filepath.Clean(path)
25		if strings.Contains(cleaned, "..") {
26			return nil, fmt.Errorf("invalid path")
27		}
28	
29		cfg, err := config.LoadWithWorkingDir(r.WorkingDir)
30		if err != nil {
31			return nil, fmt.Errorf("loading config: %w", err)
32		}
33		if cfg.Library == nil || cfg.Library.Path == "" {
34			return nil, fmt.Errorf("library not configured")
35		}
36		libPath := cfg.Library.Path
37		if !filepath.IsAbs(libPath) {
38			libPath = filepath.Join(r.WorkingDir, libPath)
39		}
40	
41		fullPath := filepath.Join(libPath, cleaned)
42		data, err := os.ReadFile(fullPath)
43		if err != nil {
44			return nil, nil // not found → null
45		}
46		content := string(data)
47	
48		// Try to enrich with docgraph metadata.
49		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
50		if err == nil {
51			if id, ok := graph.PathToID[cleaned]; ok {
52				if d, ok := graph.Documents[id]; ok {
53					doc := docToGQL(*d)
54					doc.Content = &content
55					return doc, nil
56				}
57			}
58		}
59	
60		// File exists but not in the docgraph (e.g., no DDx frontmatter).
61		return &Document{
62			ID:         cleaned,
63			Path:       cleaned,
64			DependsOn:  []string{},
65			Inputs:     []string{},
66			Dependents: []string{},
67			Content:    &content,
68		}, nil
69	}
70	
71	// Documents is the resolver for the documents field with Relay cursor pagination.
72	func (r *queryResolver) Documents(ctx context.Context, first *int, after *string, last *int, before *string, typeArg *string) (*DocumentConnection, error) {
73		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
74		if err != nil {
75			return nil, fmt.Errorf("building document graph: %w", err)
76		}
77	
78		docs := graph.AllNodesForOutput()
79		sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })
80	
81		// Apply optional type filter by path component.
82		if typeArg != nil && *typeArg != "" {
83			filtered := docs[:0]
84			for _, d := range docs {
85				if strings.Contains(d.Path, string([]rune{'/'})+*typeArg+string([]rune{'/'})) ||
86					strings.HasPrefix(d.Path, *typeArg+string([]rune{'/'})) {
87					filtered = append(filtered, d)
88				}
89			}
90			docs = filtered
91		}
92	
93		all := make([]*DocumentEdge, len(docs))
94		for i, d := range docs {
95			all[i] = &DocumentEdge{
96				Node:   docToGQL(d),
97				Cursor: encodeStableCursor(d.ID),
98			}
99		}
100	
101		startIdx := 0
102		if after != nil {
103			if afterID, ok := decodeStableCursor(*after); ok {
104				for i, e := range all {
105					if e.Node.ID == afterID {
106						startIdx = i + 1
107						break
108					}
109				}
110			}
111		}
112		endIdx := len(all)
113		if before != nil {
114			if beforeID, ok := decodeStableCursor(*before); ok {
115				for i, e := range all {
116					if e.Node.ID == beforeID {
117						endIdx = i
118						break
119					}
120				}
121			}
122		}
123		if startIdx > endIdx {
124			startIdx = endIdx
125		}
126	
127		slice := all[startIdx:endIdx]
128		if first != nil && *first >= 0 && *first < len(slice) {
129			slice = slice[:*first]
130		}
131		if last != nil && *last >= 0 && *last < len(slice) {
132			slice = slice[len(slice)-*last:]
133		}
134	
135		pageInfo := &PageInfo{
136			HasPreviousPage: startIdx > 0,
137			HasNextPage:     endIdx < len(all),
138		}
139		if len(slice) > 0 {
140			pageInfo.StartCursor = &slice[0].Cursor
141			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
142		}
143	
144		return &DocumentConnection{
145			Edges:      slice,
146			PageInfo:   pageInfo,
147			TotalCount: len(all),
148		}, nil
149	}
150	
151	// DocGraph is the resolver for the docGraph field.
152	func (r *queryResolver) DocGraph(ctx context.Context) (*DocGraph, error) {
153		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
154		if err != nil {
155			return nil, fmt.Errorf("building document graph: %w", err)
156		}
157	
158		docs := graph.AllNodesForOutput()
159		sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })
160		gqlDocs := make([]*Document, len(docs))
161		for i, d := range docs {
162			gqlDocs[i] = docToGQL(d)
163		}
164	
165		pathToIDJSON, err := json.Marshal(graph.PathToID)
166		if err != nil {
167			return nil, fmt.Errorf("serializing pathToId: %w", err)
168		}
169		dependentsJSON, err := json.Marshal(graph.Dependents)
170		if err != nil {
171			return nil, fmt.Errorf("serializing dependents: %w", err)
172		}
173	
174		warnings := graph.Warnings
175		if warnings == nil {
176			warnings = []string{}
177		}
178	
179		return &DocGraph{
180			RootDir:    graph.RootDir,
181			Documents:  gqlDocs,
182			PathToID:   string(pathToIDJSON),
183			Dependents: string(dependentsJSON),
184			Warnings:   warnings,
185		}, nil
186	}
187	
188	// docToGQL converts a docgraph.Document to the GraphQL Document model.
189	func docToGQL(d docgraph.Document) *Document {
190		doc := &Document{
191			ID:         d.ID,
192			Path:       d.Path,
193			Title:      d.Title,
194			DependsOn:  d.DependsOn,
195			Inputs:     d.Inputs,
196			Dependents: d.Dependents,
197			ParkingLot: d.ParkingLot,
198		}
199		if doc.DependsOn == nil {
200			doc.DependsOn = []string{}
201		}
202		if doc.Inputs == nil {
203			doc.Inputs = []string{}
204		}
205		if doc.Dependents == nil {
206			doc.Dependents = []string{}
207		}
208		if d.Prompt != "" {
209			p := d.Prompt
210			doc.Prompt = &p
211		}
212		if d.Review.ReviewedAt != "" || d.Review.SelfHash != "" {
213			depsJSON, _ := json.Marshal(d.Review.Deps)
214			doc.Review = &DocumentReview{
215				SelfHash:   d.Review.SelfHash,
216				Deps:       string(depsJSON),
217				ReviewedAt: d.Review.ReviewedAt,
218			}
219		}
220		if d.ExecDef != nil {
221			active := d.ExecDef.Active
222			required := d.ExecDef.Required
223			graphSource := true
224			doc.ExecDef = &DocumentExecDef{
225				ArtifactIds: d.ExecDef.ArtifactIDs,
226				Active:      &active,
227				Required:    &required,
228				GraphSource: &graphSource,
229			}
230		}
231		return doc
232	}
