71			const blocks: string[] = [];
72	
73			function textOf(node: Node) {
74				return (node.textContent ?? '').replace(/\u00a0/g, ' ').trim();
75			}
76	
77			function addBlock(value: string) {
78				const normalized = normalizeMarkdownBody(value);
79				if (normalized) blocks.push(normalized);
80			}
81	
82			for (const child of Array.from(root.childNodes)) {
83				if (child.nodeType === Node.TEXT_NODE) {
84					addBlock(child.textContent ?? '');
85					continue;
86				}
87				if (!(child instanceof HTMLElement)) continue;
88				const tag = child.tagName.toLowerCase();
