98				} else if (tag === 'pre') {
99					blocks.push(`\`\`\`\n${child.textContent ?? ''}\n\`\`\``);
100				} else if (tag === 'blockquote') {
101					addBlock(
102						textOf(child)
103							.split('\n')
104							.map((line) => `> ${line}`)
