53	// TC-GQL-004: Query.documents returns paginated documents from the working dir.
54	func TestGraphQLDocuments(t *testing.T) {
55		xdgDir := t.TempDir()
56		t.Setenv("XDG_DATA_HOME", xdgDir)
57		t.Setenv("DDX_NODE_NAME", "gql-doc-test-node")
58	
59		workDir, docIDs := setupDocTestDir(t)
60		srv := New(":0", workDir)
61	
62		body := `{"query": "{ documents { edges { node { id path title dependsOn dependents } } totalCount } }"}`
63		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewBufferString(body))
64		req.Header.Set("Content-Type", "application/json")
65		req.RemoteAddr = "127.0.0.1:12345"
66		w := httptest.NewRecorder()
67		srv.Handler().ServeHTTP(w, req)
68	
69		if w.Code != http.StatusOK {
70			t.Fatalf("expected 200, got %d: %s", w.Code, w.Body.String())
71		}
72	
73		var resp struct {
74			Data struct {
75				Documents struct {
76					Edges []struct {
77						Node struct {
78							ID         string   `json:"id"`
79							Path       string   `json:"path"`
80							Title      string   `json:"title"`
81							DependsOn  []string `json:"dependsOn"`
82							Dependents []string `json:"dependents"`
83						} `json:"node"`
84					} `json:"edges"`
85					TotalCount int `json:"totalCount"`
86				} `json:"documents"`
87			} `json:"data"`
88			Errors []struct {
89				Message string `json:"message"`
90			} `json:"errors"`
91		}
92		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
93			t.Fatalf("invalid JSON: %v\nbody: %s", err, w.Body.String())
94		}
95		if len(resp.Errors) > 0 {
96			t.Fatalf("GraphQL errors: %v", resp.Errors)
97		}
98		if resp.Data.Documents.TotalCount != len(docIDs) {
99			t.Errorf("expected totalCount=%d, got %d", len(docIDs), resp.Data.Documents.TotalCount)
100		}
101		if len(resp.Data.Documents.Edges) != len(docIDs) {
102			t.Errorf("expected %d edges, got %d", len(docIDs), len(resp.Data.Documents.Edges))
103		}
104	
105		// Verify the alpha doc has beta as a dependent.
106		foundAlpha := false
107		for _, e := range resp.Data.Documents.Edges {
108			if e.Node.ID == "alpha" {
109				foundAlpha = true
110				if len(e.Node.Dependents) != 1 || e.Node.Dependents[0] != "beta" {
111					t.Errorf("expected alpha.dependents=[beta], got %v", e.Node.Dependents)
112				}
113			}
114		}
115		if !foundAlpha {
116			t.Error("expected document with id 'alpha' in results")
117		}
118	}
