134		srv.Handler().ServeHTTP(w, req)
135	
136		if w.Code != http.StatusOK {
137			t.Fatalf("expected 200, got %d: %s", w.Code, w.Body.String())
138		}
139	
140		var resp struct {
141			Data struct {
142				DocGraph struct {
143					RootDir   string `json:"rootDir"`
144					Documents []struct {
145						ID string `json:"id"`
146					} `json:"documents"`
147					PathToID   string   `json:"pathToId"`
148					Dependents string   `json:"dependents"`
149					Warnings   []string `json:"warnings"`
150				} `json:"docGraph"`
151			} `json:"data"`
