154			} `json:"errors"`
155		}
156		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
157			t.Fatalf("invalid JSON: %v\nbody: %s", err, w.Body.String())
158		}
159		if len(resp.Errors) > 0 {
160			t.Fatalf("GraphQL errors: %v", resp.Errors)
161		}
162	
