102	func (f *CommandFactory) newDocStaleCommand() *cobra.Command {
103		cmd := &cobra.Command{
104			Use:   "stale",
105			Short: "List stale documents",
106			Args:  cobra.NoArgs,
107			RunE: func(cmd *cobra.Command, args []string) error {
108				graph, err := f.buildDocGraph()
109				if err != nil {
110					return err
111				}
112				stale := graph.StaleDocs()
113	
114				asJSON, _ := cmd.Flags().GetBool("json")
115				if asJSON {
116					enc := json.NewEncoder(cmd.OutOrStdout())
117					enc.SetIndent("", "  ")
118					return enc.Encode(stale)
119				}
120	
