484				}
485	
486				since, _ := cmd.Flags().GetString("since")
487				asJSON, _ := cmd.Flags().GetBool("json")
488	
489				gitArgs := []string{"log", "--follow", "--format=%H\t%ai\t%an\t%s"}
490				if since != "" {
491					gitArgs = append(gitArgs, since+"..HEAD")
492				}
493				gitArgs = append(gitArgs, "--", doc.Path)
494	
495				out, gitErr := exec.Command("git", gitArgs...).Output()
496				if gitErr != nil {
497					if exitErr, ok2 := gitErr.(*exec.ExitError); ok2 {
498						if strings.Contains(string(exitErr.Stderr), "not a git repository") {
499							return fmt.Errorf("not a git repository")
500						}
501					}
502					return fmt.Errorf("git log failed: %w", gitErr)
503				}
504	
505				type commitEntry struct {
506					Hash    string `json:"hash"`
507					Date    string `json:"date"`
508					Author  string `json:"author"`
509					Message string `json:"message"`
510				}
511	
512				lines := strings.Split(strings.TrimRight(string(out), "\n"), "\n")
513				entries := make([]commitEntry, 0, len(lines))
514				for _, line := range lines {
515					if line == "" {
516						continue
517					}
518					parts := strings.SplitN(line, "\t", 4)
519					if len(parts) < 4 {
520						continue
521					}
522					hash := parts[0]
523					if len(hash) > 7 {
524						hash = hash[:7]
525					}
526					date := parts[1]
527					if len(date) > 10 {
528						date = date[:10]
529					}
530					entries = append(entries, commitEntry{
531						Hash:    hash,
532						Date:    date,
533						Author:  parts[2],
534						Message: parts[3],
535					})
536				}
537	
538				if asJSON {
539					enc := json.NewEncoder(cmd.OutOrStdout())
540					enc.SetIndent("", "  ")
541					return enc.Encode(entries)
542				}
543	
544				if len(entries) == 0 {
545					fmt.Fprintln(cmd.OutOrStdout(), "No commits found.")
546					return nil
547				}
548				for _, e := range entries {
549					fmt.Fprintf(cmd.OutOrStdout(), "%s  %s  %s  %s\n", e.Hash, e.Date, e.Author, e.Message)
550				}
551				return nil
552			},
553		}
554		cmd.Flags().String("since", "", "Show commits since this ref (e.g. HEAD~10)")
555		cmd.Flags().Bool("json", false, "Output as JSON")
556		return cmd
557	}
