1095				continue
1096			}
1097			if graph != nil {
1098				if doc, ok := graph.Documents[specID]; ok && doc != nil {
1099					refs = append(refs, executeBeadGoverningRef{
1100						ID:    doc.ID,
1101						Path:  filepath.ToSlash(strings.TrimPrefix(strings.TrimPrefix(doc.Path, root), string(filepath.Separator))),
1102						Title: doc.Title,
1103					})
1104					continue
1105				}
1106			}
1107			candidate := filepath.Clean(filepath.Join(root, filepath.FromSlash(specID)))
1108			relCandidate, relErr := filepath.Rel(root, candidate)
1109			if relErr != nil || strings.HasPrefix(relCandidate, ".."+string(filepath.Separator)) || relCandidate == ".." {
1110				continue
1111			}
1112			info, statErr := os.Stat(candidate)
1113			if statErr != nil || info.IsDir() {
1114				continue
1115			}
1116			refs = append(refs, executeBeadGoverningRef{
1117				ID:   specID,
1118				Path: filepath.ToSlash(relCandidate),
