// DocumentByPath is the resolver for the documentByPath field.
// It reads the document at the given path (relative to the docgraph root or
// library) and returns its metadata plus raw file content.
func (r *queryResolver) DocumentByPath(ctx context.Context, path string) (*Document, error) {
	if path == "" {
		return nil, fmt.Errorf("path is required")
	}

	cleaned := filepath.Clean(path)
	if strings.Contains(cleaned, "..") {
		return nil, fmt.Errorf("invalid path")
	}
	// Legacy clients may emit absolute filesystem paths (bead ddx-12cae4dd)
	// produced before doc.Path was normalised. Reject them — any real document
	// resolved through the graph uses a relative path.
	if filepath.IsAbs(cleaned) {
		return nil, nil
	}

	// Prefer the docgraph-tracked location: the documents list surfaces files
	// walked under workingDir, so the detail view must read from the same root
	// (otherwise the URL for a valid list entry 404s).
	if graph, graphErr := docgraph.BuildGraphWithConfig(r.WorkingDir); graphErr == nil {
		if id, ok := graph.PathToID[cleaned]; ok {
			if d, ok := graph.Documents[id]; ok {
				absPath := d.Path
				if !filepath.IsAbs(absPath) {
					absPath = filepath.Join(graph.RootDir, absPath)
				}
				if data, readErr := os.ReadFile(absPath); readErr == nil {
					content := string(data)
					doc := docToGQL(*d)
					doc.Content = &content
					return doc, nil
				}
			}
		}
	}

	// Fall back to the configured library path so documents created via the
	// documentWrite mutation (which target the library) remain readable even
	// when they have no DDx frontmatter and so do not appear in the graph.
	cfg, err := config.LoadWithWorkingDir(r.WorkingDir)
	if err != nil {
		return nil, fmt.Errorf("loading config: %w", err)
	}
	if cfg.Library == nil || cfg.Library.Path == "" {
		return nil, nil
	}
	libPath := cfg.Library.Path
	if !filepath.IsAbs(libPath) {
		libPath = filepath.Join(r.WorkingDir, libPath)
	}

	fullPath := filepath.Join(libPath, cleaned)
	data, err := os.ReadFile(fullPath)
	if err != nil {
		return nil, nil // not found → null
	}
	content := string(data)

	return &Document{
		ID:         cleaned,
		Path:       cleaned,
		DependsOn:  []string{},
		Inputs:     []string{},
		Dependents: []string{},
		Content:    &content,
	}, nil
}

// Bead ddx-12cae4dd AC#5: documentByPath must resolve documents walked by the
// docgraph (under workingDir), not only those under the configured library.
// Before the fix, clicking a docgraph entry outside the library returned null
// and the web UI rendered "Document not found".
func TestGraphQLDocumentByPath_ResolvesDocgraphTrackedDoc(t *testing.T) {
	xdgDir := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdgDir)
	t.Setenv("DDX_NODE_NAME", "gql-doc-test-node")

	workDir := setupTestDir(t)
	docPath := filepath.Join(workDir, "docs", "resources", "agent-harness-ac.md")
	if err := os.MkdirAll(filepath.Dir(docPath), 0o755); err != nil {
		t.Fatal(err)
	}
	body := "---\nddx:\n  id: agent-harness-ac\n---\n# Agent Harness AC\n\nBody content.\n"
	if err := os.WriteFile(docPath, []byte(body), 0o644); err != nil {
		t.Fatal(err)
	}

	srv := New(":0", workDir)

	query := `{"query": "{ documentByPath(path: \"docs/resources/agent-harness-ac.md\") { id path content } }"}`
	req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewBufferString(query))
	req.Header.Set("Content-Type", "application/json")
	req.RemoteAddr = "127.0.0.1:12345"
	w := httptest.NewRecorder()
	srv.Handler().ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("expected 200, got %d: %s", w.Code, w.Body.String())
	}

	var resp struct {
		Data struct {
			DocumentByPath *struct {
				ID      string `json:"id"`
				Path    string `json:"path"`
				Content string `json:"content"`
			} `json:"documentByPath"`
		} `json:"data"`
	}
	if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
		t.Fatalf("invalid JSON: %v\nbody: %s", err, w.Body.String())
	}
	if resp.Data.DocumentByPath == nil {
		t.Fatalf("documentByPath returned null for docgraph-tracked doc; body: %s", w.Body.String())
	}
	if resp.Data.DocumentByPath.ID != "agent-harness-ac" {
		t.Errorf("got id %q, want %q", resp.Data.DocumentByPath.ID, "agent-harness-ac")
	}
	if !strings.Contains(resp.Data.DocumentByPath.Content, "Body content.") {
		t.Errorf("content missing expected body text: %q", resp.Data.DocumentByPath.Content)
	}
	if strings.HasPrefix(resp.Data.DocumentByPath.Path, "/") {
		t.Errorf("path %q leaks absolute filesystem root", resp.Data.DocumentByPath.Path)
	}
}

